#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int L[N], R[N];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &L[i], &R[i]);
        }
        int Q;
        scanf("%d", &Q);
        for (int i = 0; i < Q; i++) {
            int type;
            scanf("%d", &type);
            if (type == 1) {
                int x, y;
                scanf("%d %d", &x, &y);
                A[x - 1] = y;
            } else {
                int l, r;
                scanf("%d %d", &l, &r);
                long long sum = 0;
                for (int j = l - 1; j < r; j++) {
                    for (int k = L[j]; k <= R[j]; k++) {
                        sum += A[k - 1];
                    }
                }
                printf("%lld\n", sum);
            }
        }
    }
    return 0;
}

