import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            int[] L = new int[N];
            int[] R = new int[N];
            for (int i = 0; i < N; i++) {
                L[i] = sc.nextInt();
                R[i] = sc.nextInt();
            }
            int Q = sc.nextInt();
            for (int i = 0; i < Q; i++) {
                int type = sc.nextInt();
                if (type == 1) {
                    int x = sc.nextInt();
                    int y = sc.nextInt();
                    A[x - 1] = y;
                } else {
                    int l = sc.nextInt();
                    int r = sc.nextInt();
                    long sum = 0;
                    for (int j = l - 1; j < r; j++) {
                        for (int k = L[j]; k <= R[j]; k++) {
                            sum += A[k - 1];
                        }
                    }
                    System.out.println(sum);
                }
            }
        }
    }
}

