const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const input = () => lines[idx++].trim();
const T = parseInt(input());
for (let i = 0; i < T; i++) {
    const N = parseInt(input());
    const A = input().split(' ').map(Number);
    const L = new Array(N).fill(0);
    const R = new Array(N).fill(0);
    for (let j = 0; j < N; j++) {
        [L[j], R[j]] = input().split(' ').map(Number);
    }
    const Q = parseInt(input());
    for (let j = 0; j < Q; j++) {
        const [type, ...args] = input().split(' ').map(Number);
        if (type === 1) {
            const [x, y] = args;
            A[x - 1] = y;
        } else {
            const [l, r] = args;
            let sum = 0;
            for (let k = l - 1; k < r; k++) {
                for (let m = L[k]; m <= R[k]; m++) {
                    sum += A[m - 1];
                }
            }
            console.log(sum);
        }
    }
}
